#include <stdio.h>
#include <stdlib.h>

// Node structure
typedef struct Node {
    int val;
    struct Node *next;
} Node;

// Structure to represent queue
typedef struct LinkedListQueue {
    Node *start;
    Node *end;
    int size;
} LinkedListQueue;

// Function to create a new node
Node* createNode(int d) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    newNode->val = d;
    newNode->next = NULL;
    return newNode;
}

// Function to create a new queue
LinkedListQueue* createQueue() {
    LinkedListQueue* q = (LinkedListQueue*) malloc(sizeof(LinkedListQueue));
    q->start = q->end = NULL;
    q->size = 0;
    return q;
}

// Function to push an element in the queue
void push(LinkedListQueue* q, int x) {
    Node* element = createNode(x);
    if (q->start == NULL) {
        q->start = q->end = element;
    } else {
        q->end->next = element;
        q->end = element;
    }
    q->size++;
}

// Function to pop an element from the queue
int pop(LinkedListQueue* q) {
    if (q->start == NULL) {
        return -1;
    }
    int value = q->start->val;
    Node* temp = q->start;
    q->start = q->start->next;
    free(temp);
    q->size--;
    return value;
}

// Function to get the front element in the queue
int peek(LinkedListQueue* q) {
    if (q->start == NULL) {
        return -1;
    }
    return q->start->val;
}

// Function to check if the queue is empty
int isEmpty(LinkedListQueue* q) {
    return q->size == 0;
}

int main() {
    LinkedListQueue* q = createQueue();
    // List of commands
    char* commands[] = {"LinkedListQueue", "push", "push", "peek", "pop", "isEmpty"};
    // List of inputs
    int inputs[][10] = {{}, {3}, {7}, {}, {}, {}};
    for (int i = 0; i < 6; ++i) {
        if (strcmp(commands[i], "push") == 0) {
            push(q, inputs[i][0]);
            printf("null ");
        } else if (strcmp(commands[i], "pop") == 0) {
            printf("%d ", pop(q));
        } else if (strcmp(commands[i], "peek") == 0) {
            printf("%d ", peek(q));
        } else if (strcmp(commands[i], "isEmpty") == 0) {
            printf("%d ", isEmpty(q));
        } else if (strcmp(commands[i], "LinkedListQueue") == 0) {
            printf("null ");
        }
    }
    return 0;
}

