        Node element = new Node(x);
        if (start == null) {
            start = end = element;
        } else {
            end.next = element;
            end = element;
        }
        size++;
    }

    // Method to pop an element from the queue
    public int pop() {
        if (start == null) {
            return -1;
        }
        int value = start.val;
        Node temp = start;
        start = start.next;
        temp = null;
        size--;
        return value;
    }

